d['id']['casestudies.hero_desc']='Rekam jejak komprehensif penasihat finansial PT Chatura Indonesia dalam mengawal transaksi strategis, akuisisi lintas batas, dan restrukturisasi korporasi bernilai tinggi.';
d['id']['casestudies.metric_1_value']='USD 150 Juta+';
d['id']['casestudies.metric_1_label']='Total Nilai Transaksi Dikawal';
d['id']['casestudies.metric_2_value']='45+';
