d['id']['industries.experts_service_label']='Ahli dalam';
d['id']['industries.cta']='Hubungi Spesialis Kami';
d['id']['industries.philosophy_label']='Pendekatan Kami';
d['id']['industries.philosophy_title']='Intelijen Industri yang Mendorong Keputusan Strategis';
d['id']['industries.philosophy_desc']='Setiap industri beroperasi dalam kerangka regulasi, dinamika pasar, dan tekanan persaingan yang berbeda. Spesialis sektor kami menggabungkan pengetahuan industri mendalam dengan keahlian multi-disiplin untuk memberikan advisory yang memahami konteks bisnis Anda.';
d['id']['industries.s1_title']='Energi & Sumber Daya Alam';
d['id']['industries.s1_desc']='Sektor energi dan sumber daya alam Indonesia berada pada titik transformasi krusial. Transisi menuju energi bersih dan tuntutan keberlanjutan global mengharuskan perusahaan untuk merombak strategi operasional serta finansial mereka secara fundamental.';
d['id']['industries.s1_context']='Chatura menggabungkan keahlian industri mendalam dengan wawasan komersial untuk memandu investasi aman, penataan modal yang efisien, dan mitigasi risiko regulasi di seluruh rantai nilai energi.';
d['id']['industries.s1_svc1']='Manajemen Risiko';
d['id']['industries.s1_svc2']='Akuntansi & Keuangan';
d['id']['industries.s1_svc3']='Konsultasi Korporasi';
d['id']['industries.s2_title']='Manufaktur';
d['id']['industries.s2_desc']='Sektor manufaktur Indonesia mengalami modernisasi pesat yang didorong oleh adopsi Industri 4.0, penyesuaian rantai pasok, dan peningkatan persyaratan keberlanjutan. Perusahaan harus menyeimbangkan efisiensi operasional dengan pertumbuhan strategis.';
d['id']['industries.s2_context']='Chatura mendukung produsen dengan advisory menyeluruh mulai dari optimalisasi operasional dan penguatan rantai pasok hingga transaksi M&A dan kepatuhan regulasi di seluruh rantai nilai produksi.';
d['id']['industries.s2_svc1']='Akuntansi & Keuangan';
d['id']['industries.s2_svc2']='Manajemen Risiko';
d['id']['industries.s2_svc3']='Layanan Pajak';
d['id']['industries.s3_title']='Teknologi & Digital';
d['id']['industries.s3_desc']='Sektor teknologi Indonesia mengalami pertumbuhan tanpa preceden dengan ekonomi digital diproyeksikan mencapai USD 130 miliar. Startup, scale-up, dan perusahaan teknologi mapan menghadapi tantangan unik dalam pendanaan, skalabilitas, dan kepatuhan regulasi.';
d['id']['industries.s3_context']='Chatura menyediakan advisory khusus untuk perusahaan teknologi dalam navigasi pembiayaan venture, perpajakan digital, transaksi lintas batas, dan kesiapan IPO di lanskap regulasi yang terus berkembang.';
d['id']['industries.s3_svc1']='Konsultasi Korporasi';
d['id']['industries.s3_svc2']='Transfer Bisnis';
d['id']['industries.s3_svc3']='Layanan Pajak';
d['id']['industries.s4_title']='Kesehatan';
d['id']['industries.s4_desc']='Industri kesehatan Indonesia berkembang pesat dengan meningkatnya permintaan kelas menengah, tujuan cakupan kesehatan universal, dan inovasi kesehatan digital. Rumah sakit, perusahaan farmasi, dan startup health-tech menghadapi tantangan regulasi dan operasional yang kompleks.';
d['id']['industries.s4_context']='Chatura memberikan advisory komprehensif untuk organisasi kesehatan mulai dari transaksi grup rumah sakit dan optimalisasi pajak farmasi hingga pembiayaan venture health-tech dan kepatuhan regulasi.';
d['id']['industries.s4_svc1']='Akuntansi & Keuangan';
d['id']['industries.s4_svc2']='Layanan Pajak';
d['id']['industries.s4_svc3']='Manajemen Risiko';
d['id']['industries.s5_title']='Konsumen & Ritel';
d['id']['industries.s5_desc']='Sektor konsumen dan ritel Indonesia merupakan salah satu terbesar di Asia Tenggara, didorong oleh populasi muda yang terhubung secara digital lebih dari 270 juta jiwa. Pertumbuhan e-commerce, preferensi konsumen yang berubah, dan strategi omnichannel membentuk ulang lanskap kompetitif.';
d['id']['industries.s5_context']='Chatura mendukung brand konsumen, ritailer, dan perusahaan FMCG dengan advisory strategis mulai dari masuk pasar dan akuisisi brand hingga optimalisasi rantai pasok dan penataan struktur pajak yang efisien.';
