d['id']['legal.cookies.text_2']='Last updated: January 2026';
d['id']['legal.cookies.text_3']='This Cookies Policy explains how Chatura Indonesia uses cookies and similar technologies when you visit our website.';
d['id']['legal.cookies.text_4']='What Are Cookies';
d['id']['legal.cookies.text_5']='Cookies are small text files stored on your device when you visit a website. They help us understand how you use our site and improve your experience.';
d['id']['legal.cookies.text_6']='How We Use Cookies';
d['id']['legal.cookies.text_7']='We use cookies for analytics, functionality, and to remember your preferences. We do not use cookies for advertising purposes.';
