d['id']['legal.code_of_conduct.text_5']='We conduct our business with honesty, transparency, and fairness. We comply with all applicable laws and regulations in every jurisdiction where we operate.';
d['id']['legal.code_of_conduct.text_6']='Professional Standards';
d['id']['legal.code_of_conduct.text_7']='We maintain the highest standards of professional competence and care in delivering our services. We continuously develop our skills and knowledge.';
